from collections import defaultdict

def create_relations(people):
    relations = {"spouse": defaultdict(set), "friends": defaultdict(set)}
    for person in people:
        for friend in person.friends:
            if friend.gender != person.gender and person not in relations["spouse"][friend]:
                relations["spouse"][person].add(friend)
                relations["spouse"][friend].add(person)
            else:
                relations["friends"][person].add(friend)
                relations["friends"][friend].add(person)
    return relations

