import os

def download_book(url):
    filename = url.split('/')[-1]
    filepath = os.path.join('/tmp', filename)
    with open(filepath, 'wb') as f:
        import requests
        r = requests.get(url, stream=True)
        for chunk in r.iter_content(chunk_size=8192):
            if chunk:
                f.write(chunk)
    return filepath

