class Figure:
    def __init__(self, name, date, description):
        self.name = name
        self.date = date
        self.description = description

    def get_information(self):
        info = f"Name: {self.name}\nDate: {self.date}"
        if self.description:
            info += "\nDescription: " + self.description
        return info

    def matches_search_term(self, term):
        search_terms = ["ancient", "medieval"]

        for t in search_terms:
            t_re = re.compile(t, re.IGNORECASE)
            if t_re.search(term):
                if re.search(t_re.match(term), self.description) is not None:
                    print(f"<li>{self.get_information()}</li>")


